class Solution:
    def canIWin(self, maxChoosableInteger, desiredTotal):
        if desiredTotal <= 0:
            return True
        if maxChoosableInteger * (maxChoosableInteger + 1) // 2 < desiredTotal:
            return False
        memo = {}
        def win(remaining, target):
            if not remaining:
                return False
            key = tuple(remaining)
            if key in memo:
                return memo[key]
            res = False
            for i, v in enumerate(remaining):
                if v >= target:
                    res = True
                    break
                rest = remaining[:i] + remaining[i + 1:]
                if not win(rest, target - v):
                    res = True
                    break
            memo[key] = res
            return res
        return win(tuple(range(1, maxChoosableInteger + 1)), desiredTotal)

