class Solution:
    def canIWin(self, maxChoosableInteger, desiredTotal):
        if desiredTotal <= 0:
            return True
        if maxChoosableInteger * (maxChoosableInteger + 1) // 2 < desiredTotal:
            return False
        memo = {}
        def dfs(used, remaining):
            if used in memo:
                return memo[used]
            for n in range(1, maxChoosableInteger + 1):
                bit = 1 << (n - 1)
                if used & bit:
                    continue
                if n >= remaining or not dfs(used | bit, remaining - n):
                    memo[used] = True
                    return True
            memo[used] = False
            return False
        return dfs(0, desiredTotal)

